const recs = (n) => { const r = $(n).first().json; return (r && r.records) || []; };
const proyectos = recs('Leer Proyectos');
const voces = recs('Leer Voces');
const keywords = recs('Leer Keywords');
const referentes = recs('Leer Referentes');

const vozById = {};
const vozCritById = {};
voces.forEach(v => { const vf = v.fields || {}; vozById[v.id] = vf.nombre || ''; vozCritById[v.id] = (vf.criterios_relevancia || '').toString().trim(); });

const projects = {};
proyectos.forEach(p => {
  const f = p.fields || {};
  const vozId = Array.isArray(f.voz_default) && f.voz_default[0] ? f.voz_default[0] : null;
  projects[p.id] = {
    id: p.id, nombre: f.nombre || '',
    voz_id: vozId, voz_nombre: vozId && vozById[vozId] ? vozById[vozId] : '',
    min_likes: Number(f.min_likes || 0), min_views: Number(f.min_views || 0),
    dias_recencia: Number(f.dias_recencia || 0), top_n: Number(f.top_n || 0),
    criterios: (f.criterios_relevancia || '').toString().trim(),
    voz_criterios: vozId && vozCritById[vozId] ? vozCritById[vozId] : '',
    keywords: [], ig_handles: [], tt_handles: []
  };
});
keywords.forEach(k => {
  const f = k.fields || {}; const proy = Array.isArray(f.proyecto) ? f.proyecto[0] : null;
  if (proy && projects[proy] && f.termino) projects[proy].keywords.push(String(f.termino).trim());
});
referentes.forEach(r => {
  const f = r.fields || {}; const proy = Array.isArray(f.proyecto) ? f.proyecto[0] : null;
  const handle = String(f.handle || '').trim().replace(/^@/, '');
  if (!proy || !projects[proy] || !handle) return;
  const plat = String(f.plataforma || '').toLowerCase();
  if (plat.indexOf('insta') >= 0) projects[proy].ig_handles.push(handle);
  else if (plat.indexOf('tik') >= 0) projects[proy].tt_handles.push(handle);
});

const ig_urls = []; const ig_owner_to_proj = {};
const tt_hashtags = []; const kw_to_proj = {};
Object.values(projects).forEach(p => {
  p.ig_handles.forEach(h => { ig_urls.push('https://www.instagram.com/' + h + '/'); ig_owner_to_proj[h.toLowerCase()] = p.id; });
  p.keywords.forEach(k => { const kk = k.replace(/^#/, '').toLowerCase(); tt_hashtags.push(kk); (kw_to_proj[kk] = kw_to_proj[kk] || []).push(p.id); });
});

// ventana de recencia para el filtro de Apify: si algún proyecto pide 0 (sin límite),
// no se filtra; si no, se usa el máximo dias_recencia de los proyectos activos.
const diasVals = Object.values(projects).map(p => p.dias_recencia);
const anyUnlimited = diasVals.some(d => !d || d <= 0);
const max_dias_recencia = anyUnlimited ? 0 : Math.max.apply(null, diasVals.concat(0));

return [{ json: {
  projects, ig_urls: [...new Set(ig_urls)], tt_hashtags: [...new Set(tt_hashtags)],
  ig_owner_to_proj, kw_to_proj, active_project_ids: Object.keys(projects),
  max_dias_recencia
} }];

const plan = $('Armar plan de corrida').first().json;
const projects = plan.projects, ig_owner = plan.ig_owner_to_proj, kw = plan.kw_to_proj;
const activeIds = plan.active_project_ids || [];
const out = [];
for (const it of $input.all()) {
  const d = it.json;
  if (!d.url) continue;
  let proyId = null;
  if ((d.plataforma || '') === 'instagram') {
    const u = String(d.username || '').toLowerCase().replace(/^@/, '');
    if (ig_owner[u]) proyId = ig_owner[u];
  } else if ((d.plataforma || '') === 'tiktok') {
    const tags = String(d.hashtags || '').toLowerCase().split(',').map(s => s.trim().replace(/^#/, '')).filter(Boolean);
    for (const t of tags) { if (kw[t]) { proyId = kw[t][0]; break; } }
  }
  if (!proyId && activeIds.length === 1) proyId = activeIds[0];
  if (!proyId || !projects[proyId]) continue;
  const p = projects[proyId];
  // guardia de recencia (capa 2): descarta lo más viejo que dias_recencia del proyecto.
  // 0 = sin límite. Si no hay fecha, se conserva (no se puede juzgar la edad).
  if (p.dias_recencia > 0 && d.fecha_publicacion) {
    const ts = Date.parse(d.fecha_publicacion);
    if (Number.isFinite(ts) && (Date.now() - ts) > p.dias_recencia * 86400000) continue;
  }
  out.push({ json: Object.assign({}, d, {
    proyecto_id: proyId, proyecto_nombre: p.nombre, voz_id: p.voz_id, voz_nombre: p.voz_nombre,
    _top_n: p.top_n, _dias: p.dias_recencia, _keywords: p.keywords
  }) });
}
return out;

// Pre-trim de relevancia (Haiku) — colador LAXO sobre el caption, ANTES de transcribir.
// Optimiza recall: descarta solo lo OBVIAMENTE off-topic. Fail-open (si Haiku falla, pasa todo).
const KEY = '<ANTHROPIC_API_KEY>';
const plan = $('Armar plan de corrida').first().json || {};
const projects = plan.projects || {};
const items = $('Asignar proyecto+voz').all().map(i => i.json);

const byProj = {};
items.forEach(d => { (byProj[d.proyecto_id] = byProj[d.proyecto_id] || []).push(d); });

const drop = new Set();
for (const pid in byProj) {
  const arr = byProj[pid];
  const p = projects[pid] || {};
  const criterios = [p.criterios, p.voz_criterios].filter(Boolean).join('\n').trim();
  if (!criterios) continue; // sin rúbrica no se juzga: no se descarta nada
  const lote = arr.map(d => ({
    id: String(d.external_id || ''),
    texto: (String(d.descripcion || '') + ' ' + String(d.hashtags || '')).replace(/\s+/g, ' ').trim().slice(0, 500)
  })).filter(x => x.id);
  if (!lote.length) continue;
  const sys = 'Sos un filtro de relevancia LAXO. Te doy el tema de un proyecto, sus criterios, y una lista de videos (id + texto del caption). Devolve UNICAMENTE un JSON {"descartar":[ids]} con los ids OBVIAMENTE fuera de tema. En la duda NO descartes (preferimos dejar pasar de mas). No expliques nada.';
  const usr = 'TEMA: ' + (p.nombre || '') + '\nCRITERIOS:\n' + criterios + '\n\nVIDEOS:\n' + JSON.stringify(lote);
  try {
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.anthropic.com/v1/messages',
      headers: { 'x-api-key': KEY, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
      body: { model: 'claude-haiku-4-5', max_tokens: 1000, system: sys, messages: [{ role: 'user', content: usr }] },
      json: true,
      timeout: 30000
    });
    let txt = '';
    try { txt = (resp.content && resp.content[0] && resp.content[0].text) || ''; } catch (e) {}
    const m = String(txt).match(/\{[\s\S]*\}/);
    if (m) { const parsed = JSON.parse(m[0]); (parsed.descartar || []).forEach(id => drop.add(String(id))); }
  } catch (e) { /* fail-open: no se descarta nada de este proyecto */ }
}

const out = [];
for (const d of items) { if (!drop.has(String(d.external_id || ''))) out.push({ json: d }); }
return out;

const cfg = $('Config').first().json;
const rows = (n) => { const a = $(n).all().map(i => i.json); if (a.length === 1 && Array.isArray(a[0])) return a[0]; return a; };
const items = $('Pre-trim relevancia').all().map(i => i.json);
const seen = new Set(rows('Leer procesados').map(r => r && String(r.external_id)).filter(Boolean));
const signal = {};
rows('Leer señal selección').forEach(r => { if (r && r.referente !== undefined) signal[(r.referente || '') + '|' + (r.idioma || '')] = Number(r.tasa_seleccion || 0); });

const norm = (s) => (s || '').toString().toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
const DICT = {
  es: [' el ', ' la ', ' los ', ' las ', ' que ', ' de ', ' para ', ' con ', ' una ', ' como ', ' pero ', ' esto '],
  en: [' the ', ' and ', ' you ', ' for ', ' with ', ' this ', ' that ', ' your ', ' are ', ' have ', ' what '],
  pt: [' uma ', ' voce ', ' nao ', ' isso ', ' mais ', ' como ', ' obrigado ', ' entao ', ' muito '],
  it: [' il ', ' che ', ' per ', ' una ', ' questo ', ' come ', ' sono ', ' non ', ' anche ', ' molto '],
  fr: [' les ', ' une ', ' pour ', ' avec ', ' vous ', ' est ', ' pas ', ' comme ', ' dans ', ' mais ']
};
const guessLang = (txt) => {
  const t = ' ' + norm(txt) + ' '; let best = 'es', bestN = 0;
  for (const lng in DICT) { let n = 0; DICT[lng].forEach(w => { if (t.indexOf(w) >= 0) n++; }); if (n > bestN) { bestN = n; best = lng; } }
  return bestN === 0 ? 'es' : best;
};
const pct = (arr, v) => { if (arr.length <= 1) return 1; let c = 0; for (const x of arr) if (x <= v) c++; return c / arr.length; };

const byProj = {};
items.forEach(d => { (byProj[d.proyecto_id] = byProj[d.proyecto_id] || []).push(d); });
const out = [];
for (const pid in byProj) {
  const arr = byProj[pid];
  const views = arr.map(d => Number(d.reproducciones || 0));
  const likes = arr.map(d => Number(d.likes || 0));
  const engs = arr.map(d => parseFloat(d.engagement_rate) || 0);
  const scored = arr.map(d => {
    const v = Number(d.reproducciones || 0), l = Number(d.likes || 0), e = parseFloat(d.engagement_rate) || 0;
    const idioma = guessLang((d.descripcion || '') + ' ' + (d.bio || ''));
    const idiomaBoost = idioma !== 'es' ? Number(cfg.boost_idioma || 0.3) : 0;
    const sel = signal[(d.username || '') + '|' + idioma] || 0;
    const base = Number(cfg.peso_views || 0.4) * pct(views, v) + Number(cfg.peso_likes || 0.4) * pct(likes, l) + Number(cfg.peso_eng || 0.2) * pct(engs, e);
    const heat = base * (1 + idiomaBoost) * (1 + sel);
    return Object.assign({}, d, {
      idioma_guess: idioma, heat_score: Math.round(heat * 10000) / 10000,
      viral_por_tamano: Number(d.seguidores || 0) > Number(cfg.umbral_viral || 700000)
    });
  });
  const fresh = scored.filter(d => !seen.has(String(d.external_id)));
  fresh.sort((a, b) => b.heat_score - a.heat_score);
  const topn = Number((arr[0] && arr[0]._top_n) || cfg.top_n_fallback || 25);
  fresh.slice(0, topn).forEach(d => out.push({ json: d }));
}
return out;

// Transcribir (Supadata) — reemplaza Supadata HTTP + Merge(pos) + Parsear transcripción.
// external_id queda atado al item (mata #8). lang de Supadata primario; fallback adivina
// sobre el TRANSCRIPT, no la descripción (mata #7). Fail-open: si falla, transcripcion vacía.
const KEY = '<SUPADATA_API_KEY>';
const SLEEP_MS = 1500; // throttle (antes batchInterval 2000 con batchSize 1)
const sleep = (ms) => new Promise(r => setTimeout(r, ms));
const norm = (s) => (s || '').toString().toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
const DICT = {
  es: [' el ',' la ',' que ',' de ',' para ',' con ',' una ',' como ',' pero ',' esto '],
  en: [' the ',' and ',' you ',' for ',' with ',' this ',' that ',' your ',' are ',' what '],
  pt: [' uma ',' voce ',' nao ',' isso ',' mais ',' como ',' entao ',' muito '],
  it: [' il ',' che ',' per ',' una ',' questo ',' come ',' sono ',' non ',' molto '],
  fr: [' les ',' une ',' pour ',' avec ',' vous ',' est ',' pas ',' comme ',' mais ']
};
const guessLang = (txt) => {
  const t = ' ' + norm(txt) + ' '; let best = '', bestN = 0;
  for (const lng in DICT) { let n = 0; DICT[lng].forEach(p => { if (t.indexOf(p) >= 0) n++; }); if (n > bestN) { bestN = n; best = lng; } }
  return bestN === 0 ? '' : best;
};
const out = [];
const items = $input.all();
for (let i = 0; i < items.length; i++) {
  const d = items[i].json;
  const url = d.video_url || d.url || '';
  let txt = '', lang = '';
  if (url) {
    try {
      const resp = await this.helpers.httpRequest({
        method: 'GET',
        url: 'https://api.supadata.ai/v1/transcript?url=' + encodeURIComponent(url) + '&text=true&mode=auto',
        headers: { 'x-api-key': KEY }, json: true, timeout: 90000
      });
      txt = (typeof resp.content === 'string' && resp.content) || (typeof resp.text === 'string' && resp.text) || '';
      lang = String(resp.lang || resp.language || '').toLowerCase().slice(0, 2);
    } catch (e) { /* fail-open: sin transcript */ }
    if (i < items.length - 1) await sleep(SLEEP_MS);
  }
  txt = String(txt || '').trim().substring(0, 6000);
  const idioma = lang || guessLang(txt) || d.idioma_guess || 'es';
  out.push({ json: Object.assign({}, d, { transcripcion: txt, idioma_detectado: idioma }) });
}
return out;

// Traducir (Claude Haiku) — reemplaza IF + Script-desde-transcripción + Claude HTTP + Merge(pos) + Parsear.
// Traduce literal al español SOLO si el original no está en español. external_id atado al item (#8).
// Fail-open: si la traducción falla o devuelve vacío, el script queda como el transcript original.
const KEY = '<ANTHROPIC_API_KEY>';
const SLEEP_MS = 1000; // throttle (antes batchInterval 1000)
const sleep = (ms) => new Promise(r => setTimeout(r, ms));
const SYS = 'Sos un traductor literal. Traduci el texto al espanol neutro de forma fiel y literal: sin reescribir, sin resumir, sin embellecer, sin agregar ni quitar nada; conserva el sentido y el orden. Devolve UNICAMENTE el texto traducido, sin comillas ni comentarios.';
const out = [];
const items = $input.all();
for (let i = 0; i < items.length; i++) {
  const d = items[i].json;
  const transcript = String(d.transcripcion || '');
  const idioma = d.idioma_detectado || d.idioma_guess || 'es';
  let script = transcript;
  if (transcript && idioma !== 'es') {
    try {
      const resp = await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://api.anthropic.com/v1/messages',
        headers: { 'x-api-key': KEY, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
        body: { model: 'claude-haiku-4-5', max_tokens: 2000, system: SYS, messages: [{ role: 'user', content: transcript.substring(0, 6000) }] },
        json: true, timeout: 60000
      });
      let tr = '';
      try { tr = (resp.content && resp.content[0] && resp.content[0].text) || ''; } catch (e) {}
      tr = String(tr || '').trim();
      if (tr) script = tr;
    } catch (e) { /* fail-open: script = transcript */ }
    if (i < items.length - 1) await sleep(SLEEP_MS);
  }
  out.push({ json: Object.assign({}, d, { script: script, idioma: idioma }) });
}
return out;

// Gate de relevancia (Haiku) — jurado ESTRICTO sobre el transcript (precision). Llena CALIDAD (PLAN §2.4).
// Juzga relevancia/calidad contra criterios_relevancia (Proyecto ⊕ Voz) → {relevante, score, razon}.
// Dropea los relevante:false. Composite: heat = PESO·score_haiku + (1-PESO)·percentil(prescore métrico).
// Fail-open: sin criterios o si Haiku falla, pasa todo y ordena por el prescore métrico.
const KEY = '<ANTHROPIC_API_KEY>';
const cfg = $('Config').first().json;
const PESO = Number(cfg.peso_relevancia != null ? cfg.peso_relevancia : 0.7);
const projects = ($('Armar plan de corrida').first().json || {}).projects || {};
const SLEEP_MS = 1000;
const sleep = (ms) => new Promise(r => setTimeout(r, ms));
const pct = (arr, v) => { if (arr.length <= 1) return 1; let c = 0; for (const x of arr) if (x <= v) c++; return c / arr.length; };

const items = $input.all().map(i => i.json);
const byProj = {};
items.forEach(d => { (byProj[d.proyecto_id] = byProj[d.proyecto_id] || []).push(d); });

const out = [];
let first = true;
for (const pid in byProj) {
  const arr = byProj[pid];
  const p = projects[pid] || {};
  const criterios = [p.criterios, p.voz_criterios].filter(Boolean).join('\n').trim();
  const juicio = {}; // external_id → { relevante, score, razon }
  if (criterios) {
    const lote = arr.map(d => ({ id: String(d.external_id || ''), texto: String(d.script || '').replace(/\s+/g, ' ').trim().slice(0, 1500) })).filter(x => x.id && x.texto);
    if (lote.length) {
      if (!first) await sleep(SLEEP_MS); first = false;
      const sys = 'Sos un jurado ESTRICTO de relevancia y calidad. Te doy el tema de un proyecto, sus criterios, y una lista de videos (id + transcript). Para cada uno decidi si es RELEVANTE y UTIL segun los criterios. Precision: ante la duda, marca relevante:false. Devolve UNICAMENTE un JSON {"juicio":[{"id":"...","relevante":true,"score":0.0,"razon":"breve"}]}. score 0..1 = que tan bien cumple los criterios.';
      const usr = 'TEMA: ' + (p.nombre || '') + '\nCRITERIOS:\n' + criterios + '\n\nVIDEOS:\n' + JSON.stringify(lote);
      try {
        const resp = await this.helpers.httpRequest({
          method: 'POST', url: 'https://api.anthropic.com/v1/messages',
          headers: { 'x-api-key': KEY, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
          body: { model: 'claude-haiku-4-5', max_tokens: 4000, system: sys, messages: [{ role: 'user', content: usr }] },
          json: true, timeout: 60000
        });
        let txt = '';
        try { txt = (resp.content && resp.content[0] && resp.content[0].text) || ''; } catch (e) {}
        const m = String(txt).match(/\{[\s\S]*\}/);
        if (m) { const parsed = JSON.parse(m[0]); (parsed.juicio || []).forEach(j => { juicio[String(j.id)] = j; }); }
      } catch (e) { /* fail-open: juicio vacío → todos pasan, ordena por métrica */ }
    }
  }
  const kept = arr.filter(d => { const j = juicio[String(d.external_id)]; return !(j && j.relevante === false); });
  const prescores = kept.map(d => Number(d.heat_score || 0));
  kept.forEach(d => {
    const j = juicio[String(d.external_id)];
    const sHaiku = j && typeof j.score === 'number' ? Math.max(0, Math.min(1, j.score)) : null;
    const metricPct = pct(prescores, Number(d.heat_score || 0));
    const composite = sHaiku != null ? (PESO * sHaiku + (1 - PESO) * metricPct) : metricPct;
    out.push({ json: Object.assign({}, d, {
      prescore_metrico: Number(d.heat_score || 0),
      relevancia_score: sHaiku,
      relevancia_razon: (j && j.razon) || '',
      heat_score: Math.round(composite * 10000) / 10000
    }) });
  });
}
return out;

const out = [];
for (const it of $input.all()) {
  const d = it.json;
  const titulo = String(d.descripcion || '').replace(/\s+/g, ' ').trim().slice(0, 80) || (d.username || 'video');
  out.push({ json: {
    titulo,
    script: String(d.script || '').slice(0, 95000),
    idioma: d.idioma || d.idioma_detectado || '',
    proyecto_id: d.proyecto_id || null, proyecto_nombre: d.proyecto_nombre || '',
    voz_id: d.voz_id || null, voz_nombre: d.voz_nombre || '',
    referente: d.username || '', url_referente: d.url || '',
    views: Number(d.reproducciones || 0), likes: Number(d.likes || 0),
    seguidores: Number(d.seguidores || 0), engagement: parseFloat(d.engagement_rate) || 0,
    heat_score: Number(d.heat_score || 0), viral_por_tamano: !!d.viral_por_tamano,
    plataforma: d.plataforma || '', external_id: String(d.external_id || ''),
    relevancia_score: (d.relevancia_score != null ? d.relevancia_score : null),
    relevancia_razon: d.relevancia_razon || '', thumbnail_url: d.thumbnail_url || ''
  } });
}
return out;

const recs = $input.all().map(i => {
  const d = i.json;
  const f = {
    titulo: d.titulo, script: d.script, idioma: d.idioma || undefined,
    referente: d.referente, url_referente: d.url_referente,
    views: d.views, likes: d.likes, seguidores: d.seguidores, engagement: d.engagement,
    heat_score: d.heat_score, viral_por_tamano: d.viral_por_tamano,
    relevancia_score: (d.relevancia_score != null ? d.relevancia_score : undefined),
    relevancia_razon: d.relevancia_razon || undefined, estado: 'nuevo'
  };
  if (d.proyecto_id) f.proyecto = [d.proyecto_id];
  if (d.voz_id) f.voz = [d.voz_id];
  if (d.thumbnail_url) f.thumbnail = [{ url: d.thumbnail_url }];
  return { fields: f };
});
const out = [];
for (let i = 0; i < recs.length; i += 10) out.push({ json: { records: recs.slice(i, i + 10), typecast: true } });
return out.length ? out : [];

const run = $('Abrir run en el registro').first().json || {};
const run_id = run.id || null;
const outputs = $input.all().map(i => {
  const d = i.json;
  return {
    run_id, external_id: d.external_id || null, tipo: 'guion_reel', titulo: d.titulo || '(sin titulo)',
    contenido_o_link: d.script || '', estado: 'draft',
    source_items: [{ platform: d.plataforma || '', url: d.url_referente || '' }],
    metadata: {
      proyecto: d.proyecto_nombre || '', voz: d.voz_nombre || '', referente: d.referente || '',
      url_referente: d.url_referente || '', idioma: d.idioma || '',
      views: d.views || 0, likes: d.likes || 0, seguidores: d.seguidores || 0,
      engagement: d.engagement || 0, heat_score: d.heat_score || 0, link_doc: ''
    }
  };
});
return [{ json: { run_id, n: outputs.length, outputs } }];

const cfg = $('Config').first().json;
const iid = cfg.instance_id && String(cfg.instance_id).indexOf('<<') < 0 ? cfg.instance_id : null;
const batch = $input.all().map(i => {
  const d = i.json;
  return {
    instance_id: iid, platform: d.plataforma || '', external_id: String(d.external_id || ''),
    url: d.url || '', seguidores: Number(d.seguidores || 0),
    flag_viral: !!d.viral_por_tamano, idioma: d.idioma_guess || null
  };
}).filter(r => r.external_id);
return [{ json: { batch } }];
